package main

import (
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

var (
	webhookConfig struct {
		WebhookURL string `json:"webhook_url"`
	}
	configMu sync.Mutex
)

type WebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

type WebhookResponse struct {
	Success    bool   `json:"success"`
	Message    string `json:"message"`
	WebhookURL string `json:"webhook_url,omitempty"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookRequest

	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "Invalid request body: " + err.Error(),
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Validate the webhook URL by sending a test GET request with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook URL validation failed: %s", err.Error()),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook URL returned non-success status code: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	configMu.Lock()
	webhookConfig.WebhookURL = req.WebhookURL
	configMu.Unlock()

	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Success:    true,
		Message:    "Webhook configured successfully",
		WebhookURL: req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/webhook/configure", ConfigureWebhook)

	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

