			Message: fmt.Sprintf("Webhook URL validation failed: %s", err.Error()),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(WebhookResponse{
			Success: false,
			Message: fmt.Sprintf("Webhook URL returned non-success status code: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	configMu.Lock()
	webhookConfig.WebhookURL = req.WebhookURL
	configMu.Unlock()

	return ctx.Status(fiber.StatusOK).JSON(WebhookResponse{
		Success:    true,
		Message:    "Webhook configured successfully",
		WebhookURL: req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/webhook/configure", ConfigureWebhook)

	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

