	if hostLower == "localhost" || hostLower == "0.0.0.0" || hostLower == "[::1]" || hostLower == "::1" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must not point to a private or reserved IP address",
		})
	}

