package main

import (
	"context"
	"errors"
	"fmt"
	"net"
	"net/http"
	"net/url"
	"strings"
	"time"

	"github.com/gofiber/fiber/v2"
)

// webhookRequest represents the expected JSON request body
type webhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// isPrivateIP checks if an IP address is in a private/reserved range
func isPrivateIP(ip net.IP) bool {
	privateRanges := []string{
		"127.0.0.0/8",       // Loopback
		"10.0.0.0/8",        // Private A
		"172.16.0.0/12",     // Private B
		"192.168.0.0/16",    // Private C
		"169.254.0.0/16",    // Link-local
		"0.0.0.0/8",         // Current network
		"100.64.0.0/10",     // Shared address space
		"192.0.0.0/24",      // IETF Protocol Assignments
		"192.0.2.0/24",      // TEST-NET-1
		"198.51.100.0/24",   // TEST-NET-2
		"203.0.113.0/24",    // TEST-NET-3
		"224.0.0.0/4",       // Multicast
		"240.0.0.0/4",       // Reserved
		"255.255.255.255/32", // Broadcast
		"::1/128",           // IPv6 loopback
		"fc00::/7",          // IPv6 unique local
		"fe80::/10",         // IPv6 link-local
	}

	for _, cidr := range privateRanges {
		_, network, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if network.Contains(ip) {
			return true
		}
	}

	return false
}

// resolveAndValidateHost resolves the hostname and returns the resolved IPs if they are not private.
func resolveAndValidateHost(host string) ([]net.IP, error) {
	// Remove port if present
	hostname := host
	if h, _, err := net.SplitHostPort(host); err == nil {
		hostname = h
	}

	// Check if the host is an IP address directly
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip) {
			return nil, errors.New("webhook URL must not point to a private or reserved IP address")
		}
		return []net.IP{ip}, nil
	}

	// Resolve the hostname
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return nil, errors.New("unable to resolve webhook URL hostname")
	}

	if len(ips) == 0 {
		return nil, errors.New("webhook URL hostname did not resolve to any IP")
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return nil, errors.New("webhook URL must not point to a private or reserved IP address")
		}
	}

	return ips, nil
}

// ConfigureWebhook handles POST requests to configure a webhook URL
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse the JSON request body
	var req webhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid JSON format",
		})
	}

