	if parsedURL.Host == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must have a valid host",
		})
	}

	// Block common localhost variations
	hostLower := strings.ToLower(parsedURL.Hostname())
	if hostLower == "localhost" || hostLower == "0.0.0.0" || hostLower == "[::1]" || hostLower == "::1" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
