package main

import (
	"net/http"
	"sync"
	"time"

	"github.com/gofiber/fiber/v2"
)

type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

var (
	savedConfig WebhookConfig
	configMu    sync.Mutex
)

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var req WebhookConfig

	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid request body",
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "webhook_url is required",
		})
	}

	// Validate the webhook URL by sending a test GET request with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Webhook URL returned non-success status code",
		})
	}

	// Save the configuration
	configMu.Lock()
	savedConfig = req
	configMu.Unlock()

	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success":     true,
		"message":     "Webhook configured successfully",
		"webhook_url": req.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	app.Listen(":3000")
}

